examples.advancedGet:
function runGet() {
  const state = ctx.Request.URL.Query().Get('address.state') || 'nc';
  let schemaSlug = `prospect_${state.toLowerCase()}`;
  let referrals = ctx.DB.Find(rdx.ConnName, rdx.DBName, '_referral', {referral_source_type: 'dealer'}) || [];
  let scripts = ctx.DB.Find(rdx.ConnName, rdx.DBName, '_web_pilot', {tags: {"$all": [`AUTO-${state}`]}}, null, {slug: 1}, 0, 20) || [];
  if (ctx.RecordID === 'create') {
    let overrides = ctx.ExtractQueryParams(['address.state', 'quote.insurance_type']);
    let record = ctx.DB.CreateNewWithOverrides(rdx.ConnName, rdx.DBName, schemaSlug, ctx.Username, overrides);
    return {record, referrals, web_pilot_runs: [], scripts};
  }
  let id = ctx.RecordID;
  let dataObjID = ObjectIDFromHex(id);
  let web_pilot_runs = ctx.DB.Find(rdx.ConnName, rdx.DBName, '_web_pilot_run', {data_id: dataObjID}) || [];
  let record = ctx.DB.FindByID(rdx.ConnName, rdx.DBName, 'prospect', id);
  return {record, referrals, web_pilot_runs, scripts};
}

examples.arrayDelete:
function runDelete() {
  let collection = 'prospect';
  let id = ctx.RecordID;
  let index = ctx.RecordIndex;
  let arrayField = ctx.Request.URL.Query().Get('array_field');
  if (arrayField && index !== '') {
    const ALLOWED_ARRAY_FIELDS = ['household_members', 'household_vehicles'];
    if (!ALLOWED_ARRAY_FIELDS.includes(arrayField)) throw new Error('Deletion not allowed');
    let record = ctx.DB.FindByID(rdx.ConnName, rdx.DBName, collection, id);
    let arr = record[arrayField];
    arr.splice(parseInt(index, 10), 1);
    let updateDoc = {};
    updateDoc[arrayField] = arr;
    ctx.DB.UpdateByID(rdx.ConnName, rdx.DBName, collection, id, updateDoc, null);
    return {success: true};
  }
  ctx.DB.DeleteByID(rdx.ConnName, rdx.DBName, collection, id);
  return {success: true};
}

